window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2022>1","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"A prerequisite for orderliness is","images":[],"options":{"A":"humility","B":"morality","C":"hardwork","D":"politeness"},"answer":"B","explanation":"Orderliness is a prerequisite for morality. Morality involves understanding and adhering to the rules and standards set by society, which promotes orderliness. Humility, hardwork, and politeness are virtues that can contribute to orderliness, but they are not prerequisites.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>2","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"National symbols are also referred to a symbols of national","images":[],"options":{"A":"co-operation","B":"identity","C":"unity","D":"development"},"answer":"B","explanation":"National symbols are referred to as symbols of national identity. They represent the values, history, and cultural heritage of a nation, thereby creating a sense of identity among its citizens. Examples of national symbols include the national flag, national anthem, national bird, etc.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>3","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Law of libel and defamation of character violates right to freedom of","images":[],"options":{"A":"fair hearing","B":"religion","C":"expression","D":"association"},"answer":"C","explanation":"The law of libel and defamation of character violates the right to freedom of expression. Freedom of expression is a fundamental human right that allows individuals to freely express their thoughts, ideas, and opinions. However, this right is not absolute and can be limited to protect the reputation and rights of others. Libel and defamation are legal terms for false statements that harm the reputation of an individual or entity, and making such statements can be considered a violation of their right to freedom of expression.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>4","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS","question":"Who among the following is not a foremost Nigerian nationalist?","images":[],"options":{"A":"Sir Abubakar Tafawa Balewa","B":"Dr. Nnamdi Azikwe","C":"General Yakubu Gowon","D":"Chief Obafemi Awolowo"},"answer":"C","explanation":"General Yakubu Gowon is not considered a foremost Nigerian nationalist. The term 'nationalist' refers to a person who advocates for political independence for a country. While Gowon played a significant role in Nigeria's history as the head of state during the Nigerian Civil War, he is not typically categorized as a nationalist. The other individuals listed, Sir Abubakar Tafawa Balewa, Dr. Nnamdi Azikwe, and Chief Obafemi Awolowo, are well-known nationalists who played key roles in Nigeria's struggle for independence.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>5","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : TRAFFIC REGULATION AND ITS IMPORTANCE IN THE SOCIETY","question":"The major reason for the enactment of traffic regulations is to","images":[],"options":{"A":"make sure people travel for business purpose.","B":"arrest traffic offenders and violators.","C":"ensure safety and allow easy flow of traffic","D":"ensure the sustenance and longevity of the roads."},"answer":"C","explanation":"The major reason for the enactment of traffic regulations is to ensure safety and allow easy flow of traffic. Traffic regulations are rules or guidelines created by traffic authorities to guide the behavior of road users. This is done to ensure safety on the roads and to prevent accidents and traffic jams. While arresting traffic offenders and ensuring the longevity of roads may be secondary benefits, they are not the primary reason for traffic regulations.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>6","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"The basic responsibility of parents is","images":[],"options":{"A":"providing necessities of life for the children.","B":"buying expensive gifts for the children.","C":"sending the children abroad for quality education.","D":"visiting site of attraction with the children."},"answer":"A","explanation":"The basic responsibility of parents is to provide the necessities of life for their children. This includes providing food, shelter, clothing, education, and healthcare. While the other options may be things that parents can do for their children, they are not considered basic responsibilities.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>7","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS","question":"The attitude that prevents peaceful resolution of inter-communal conflict is","images":[],"options":{"A":"conciliation","B":"resentment","C":"dialogue","D":"mediation"},"answer":"B","explanation":"Resentment is an attitude that can prevent the peaceful resolution of inter-communal conflict. Resentment is a feeling of anger or displeasure about someone or something unfair. It can lead to unwillingness to forgive or forget past wrongs, which can hinder dialogue, mediation, and conciliation efforts. The other options - conciliation, dialogue, and mediation are actually methods used to resolve conflicts, not attitudes that prevent resolution.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>8","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Use the passage below to answer the question.    It is a common practice for the youths of Upe village to meet every last Saturday of the month to build a proposed structure. Through this practice, they have successfully built a monumental market complex which attracts people from neighboring villages.    The zeal shown by the youths of Upe village is a manifestation of","images":[],"options":{"A":"community service","B":"political participation","C":"national development","D":"town planning"},"answer":"A","explanation":"The zeal shown by the youths of Upe village is a manifestation of community service. Community service is a voluntary work intended to help people in a particular area. In this case, the youths of Upe village are voluntarily coming together to build a proposed structure which benefits their community.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>9","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Use the passage below to answer the question.    It is a common practice for the youths of Upe village to meet every last Saturday of the month to build a proposed structure. Through this practice, they have successfully built a monumental market complex which attracts people from neighboring villages.  The youth who took part in the various building projects in Upe village are said to be","images":[],"options":{"A":"reliable","B":"self-reliant","C":"hardworking","D":"selfless"},"answer":"D","explanation":"The youth who took part in the various building projects in Upe village are said to be selfless. Selflessness is the quality of caring more about other people's needs and interests than about your own. In this case, the youths of Upe village are putting the needs of their community before their own by voluntarily participating in the building projects.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>10","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"Which of the following sets of agencies are responsible for checking road worthiness of vehicles?","images":[],"options":{"A":"The Federal Road Safety Corps and Vehicle Inspection Office","B":"The Police and National Security and Civil Defence Corps","C":"Federal Road Safety Corps and the Nigerian Army","D":"The Nigerian Army and Vehicle Inspection Office"},"answer":"A","explanation":"The Federal Road Safety Corps (FRSC) and Vehicle Inspection Office (VIO) are the agencies responsible for checking the roadworthiness of vehicles in Nigeria. The FRSC is the Government Agency with statutory responsibilities for road safety administration in Nigeria. It is responsible for ensuring that vehicles on the road are safe to drive. The VIO, on the other hand, is a service in all states of Nigeria for road traffic administration and control. They are responsible for issuing vehicle licenses and ensuring that vehicles are roadworthy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>11","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"Which of the following may not be vested with a constitution authority?","images":[],"options":{"A":"A family","B":"A mob","C":"A school","D":"The state"},"answer":"B","explanation":"A mob is not vested with constitutional authority. A mob is a large crowd of people, especially one that is disorderly and intent on causing trouble or violence. They are not organized or recognized by the constitution as a body with authority. On the other hand, a family, a school, and the state are all recognized by the constitution and have certain authorities vested in them.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>12","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"An individual who finds it difficult to do without in-take of prohibited substances is","images":[],"options":{"A":"a human trafficker","B":"an armed robber","C":"a drug addict","D":"a kidnapper"},"answer":"C","explanation":"The question is about an individual who finds it difficult to do without in-take of prohibited substances. This is a clear description of a drug addict. A drug addict is a person who is unable to stop using a drug, despite harmful consequences to their health and personal life. The other options (human trafficker, armed robber, kidnapper) do not fit this description.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>13","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING","question":"Which of the following is not a method of recruiting victims for human trafficking?","images":[],"options":{"A":"Deceit","B":"Threat","C":"Application","D":"Abduction"},"answer":"C","explanation":"The question asks for a method that is not used for recruiting victims for human trafficking. The options provided are Deceit, Threat, Application, and Abduction. The correct answer is 'Application'. Human trafficking involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. While deceit, threat, and abduction are common methods used by traffickers, 'application' is not a recognized method of recruitment in human trafficking. It implies a formal, voluntary process, which is not characteristic of human trafficking.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>14","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW","question":"The law protecting certain individuals from being prosecuted is called","images":[],"options":{"A":"penal code.","B":"constitutional protection.","C":"immunity clause.","D":"legal rights."},"answer":"C","explanation":"The law protecting certain individuals from being prosecuted is called the immunity clause. This is a provision in the constitution that grants certain public officials, especially high-ranking executives, immunity from legal suits and prosecution for actions conducted in their official capacity. It is designed to allow such officials to perform their duties without fear of constant litigation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>15","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD","question":"Use the image to answer the question.        We can conclude that the mother of the boy putting on a face cap in the cartoon in the image  is a","images":["data:image/png;base64,"],"options":{"A":"religious mother","B":"responsible parent","C":"wealthy person","D":"child activist"},"answer":"B","explanation":"We can conclude that the mother of the boy putting on face cap is a responsible mother as she taught him good morals and abided by it.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>16","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION","question":"Use the image to answer the question.        The effect of the interaction as captured in the cartoon, in the Fig. in relation to Civic Education is","images":["data:image/png;base64,"],"options":{"A":"mass mobilization","B":"pressure group","C":"peer pressure","D":"popular participation"},"answer":"C","explanation":"Peer pressure is the direct or indirect influence on peers, i.e., members of social groups with similar interests, experiences, or social statuses. Members of a peer group are more likely to influence a person's beliefs, values, and behaviour.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>17","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"Use the image to answer the question.        We can make inference from the response of the boy wearing short pants in the cartoon, in the image that he","images":["data:image/png;base64,"],"options":{"A":"needs the knowledge of Civic Education.","B":"became industrious through empowerment.","C":"gets financial support from his family.","D":"lacks moral care of a responsible parent."},"answer":"D","explanation":"Self-explanatory as this is the most appropriate answer.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>18","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD","question":"Use the image to answer the question.        Which of the following is not  an advisable way through which the orientation of the boy wearing short pants in the cartoon, in the image can be corrected?","images":["data:image/png;base64,"],"options":{"A":"Subjecting him to harsh punitive measures.","B":"Impacting an effective Civic Education in him.","C":"He needs morally upright and responsible parenting.","D":"An effective guidance and counselling section."},"answer":"C","explanation":"Moral  upbringing is a basic responsibility of the parent.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>19","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS","question":"Limitation to the right of life can be found in the case of","images":[],"options":{"A":"an imprisoned person","B":"a kidnapped person","C":"a condemned person","D":"a trafficked person"},"answer":"C","explanation":"Limitation to the right of life can be found in the case of a condemned person. This refers to a person who has been sentenced to death by a competent court of law for committing a capital offence. In such cases, the right to life is legally limited as a form of punishment for the crime committed.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>20","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS","question":"In which of the following do citizens have equal rights? Right to","images":[],"options":{"A":"freedom of movement","B":"freedom from discrimination","C":"free education","D":"form or join any political party"},"answer":"B","explanation":"In the context of citizen's rights, the 'freedom from discrimination' implies that all citizens have equal rights regardless of their race, religion, sex, age, and other personal characteristics. This means that every citizen is treated equally under the law and has equal access to social goods and services. The other options, while they are rights, do not inherently imply equality among citizens.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>21","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION","question":"Interest and willingness to participate in the affairs of a nation are forms of","images":[],"options":{"A":"Popular Participation","B":"National Consciousness","C":"Political Apathy","D":"Citizenship Education"},"answer":"A","explanation":"Interest and willingness to participate in the affairs of a nation are forms of 'Popular Participation'. This refers to the involvement of citizens in decision-making processes, implementation, and evaluation of policies and projects. 'National Consciousness' refers to the awareness of being part of a nation and having a sense of belonging. 'Political Apathy' refers to indifference towards political activities and 'Citizenship Education' is about educating citizens about their rights, responsibilities, and the workings of the government.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>22","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"The societal norms that represents the overall attitude of the people in a society is called","images":[],"options":{"A":"group values.","B":"general  values.","C":"religious values.","D":"personal values."},"answer":"B","explanation":"The societal norms that represent the overall attitude of the people in a society are referred to as general values. These are the values that are widely accepted and followed by the majority of people in a society. They are not specific to any group, religion, or individual, hence the term 'general'.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>23","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS","question":"My stiffest earthly assignment is ended and major life's work is done. My country is now free...        -  Dr. Nnamdi Azikiwe     The speaker quoted above must have fought hard for national","images":[],"options":{"A":"prosperity","B":"recognition","C":"development","D":"independence"},"answer":"D","explanation":"The quote is from Dr. Nnamdi Azikiwe, who was one of the leading figures in Nigeria's struggle for independence from British rule. The phrase 'My country is now free' indicates that the speaker was involved in a struggle for national independence, not prosperity, recognition, or development. Therefore, the correct answer is 'independence'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>24","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT","question":"Irresponsible parenting has the tendency of","images":[],"options":{"A":"encouraging egoistic tendencies","B":"preserving of culture","C":"promoting of positive values","D":"promoting peaceful co-existence"},"answer":"A","explanation":"Irresponsible parenting can lead to children developing egoistic tendencies. This is because when parents do not fulfill their responsibilities, children may grow up thinking only about their own needs and wants, without considering the needs and wants of others. This is what is referred to as egoistic tendencies.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>25","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY","question":"Which of the following is a cause of political apathy in Nigeria?","images":[],"options":{"A":"Adequate citizenship education","B":"A free and fair election","C":"Biased electoral umpires","D":"Adequate political awareness"},"answer":"C","explanation":"Biased electoral umpires can cause political apathy in Nigeria. Political apathy refers to a lack of interest in political activities, such as voting in elections. When electoral umpires are biased, they may not conduct free and fair elections, which can lead to citizens losing faith in the electoral process and becoming apathetic.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>26","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"Representation of Nigerians in the senate is","images":[],"options":{"A":"Proportional","B":"collegial","C":"equal","D":"unequal"},"answer":"C","explanation":"Representation of Nigerians in the Senate is equal. This is because each state, regardless of its size or population, is represented by three senators. This ensures that all states have an equal voice in the Senate.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>27","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS","question":"Identify the odd one from the list below in relation to citizenship obligations","images":[],"options":{"A":"Payment of tax","B":"Right to personal liberty","C":"Protection of public utilities","D":"Obedience to the Law"},"answer":"B","explanation":"The odd one from the list in relation to citizenship obligations is 'Right to personal liberty'. This is because it is a fundamental human right, not an obligation. The other options - 'Payment of tax', 'Protection of public utilities', and 'Obedience to the Law' - are all obligations of a citizen.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>28","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"According to the 1999 constitution as amended, sovereignty belongs to the","images":[],"options":{"A":"president who is also the Commander-in-Chief of the Armed Forces.","B":"people from whom government derives its power and authority.","C":"National Assembly which has power to make laws and amend the constitution.","D":"judiciary which interprets the laws of the state"},"answer":"B","explanation":"According to the 1999 constitution as amended, sovereignty belongs to the people from whom government derives its power and authority. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. In this case, the people are the source of power and authority for the government.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>29","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Article 1 of the Universal Declaration of Human Rights (UDHR) states that all human beings","images":[],"options":{"A":"have freedom of movement","B":"are born free and equal","C":"should be free from torture","D":"have the right to recognition"},"answer":"B","explanation":"Article 1 of the Universal Declaration of Human Rights (UDHR) states that all human beings are born free and equal in dignity and rights. They are endowed with reason and conscience and should act towards one another in a spirit of brotherhood. This means that every person is entitled to certain fundamental rights, simply by the fact of being human. These rights are not granted by any state. These universal rights are inherent to us all, regardless of nationality, sex, national or ethnic origin, color, religion, language, or any other status.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>30","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"Use the quotation below to answer the question.     If you cannot beat them, join them.     The statement is an indication of a society that is","images":[],"options":{"A":"ethically upright","B":"morally degenerated","C":"politically disintegrated","D":"socially regenerated"},"answer":"B","explanation":"The statement 'If you cannot beat them, join them' is often used to express a form of surrender or compromise, especially when one is unable to overcome a particular challenge or situation. It suggests a form of moral degeneration as it implies giving up on one's principles or values to conform to the majority or the status quo, even if it's wrong or unethical. Therefore, the statement is an indication of a society that is morally degenerated.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>31","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"Use the quotation below to answer the question.     If you cannot beat them, join them.   Through which of the following means can the effect of the above quotation on the society be rectified?","images":[],"options":{"A":"Compulsory communal service","B":"Strengthening of the constitution","C":"Reorientation of values","D":"Distribution of relief materials during emergency"},"answer":"C","explanation":"The effect of the quotation 'If you cannot beat them, join them' on the society can be rectified through the reorientation of values. This means educating the members of the society about the importance of upholding their principles and values, even when faced with challenges or opposition. It involves teaching them to stand for what is right, even if it means standing alone, rather than conforming to the majority or the status quo, especially when it's wrong or unethical. Therefore, the reorientation of values is the means through which the effect of the above quotation on the society can be rectified.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>32","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS","question":"Interpersonal relationship is promoted through the following ways except","images":[],"options":{"A":"confrontation","B":"healthy competition","C":"co-operation","D":"communal living"},"answer":"A","explanation":"Interpersonal relationship is promoted through healthy competition, co-operation, and communal living. These are all ways that encourage positive interaction, mutual understanding, and respect among individuals. However, confrontation does not promote interpersonal relationships. Confrontation often leads to conflicts, disagreements, and can strain relationships.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>33","subject":"Civic Education","year":"2022","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM","question":"An activity meant to promote and protect the interest of a country is","images":[],"options":{"A":"unitarianism","B":"communism","C":"communalism","D":"nationalism"},"answer":"D","explanation":"Nationalism is an activity meant to promote and protect the interest of a country. It involves the actions and policies that are aimed at achieving and maintaining the unity, integrity, and identity of a nation. Unitarianism, communism, and communalism are forms of political ideologies or systems, but they do not inherently promote and protect the interest of a country in the way that nationalism does.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>34","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY","question":"Democracy is important because it","images":[],"options":{"A":"accommodates popular participation.","B":"accommodates political apathy.","C":"encourages operational bureaucracy.","D":"breeds ethnic competition and rivalry."},"answer":"A","explanation":"Democracy is a system of government where citizens exercise power by voting. It is important because it accommodates popular participation. This means that in a democratic system, every citizen has the right to participate in the decision-making process, either directly or through elected representatives. This is not the case with political apathy, operational bureaucracy, or ethnic competition and rivalry, which are not inherent characteristics of democracy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>35","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Which of the following criminal act is most commonly perpetrated by cult members?","images":[],"options":{"A":"Prostitution","B":"Money Laundering","C":"Corruption","D":"Violence"},"answer":"D","explanation":"Cultism is often associated with violence. Cult members are known to engage in violent activities such as fights, murders, and other forms of physical aggression. While cult members may also engage in other criminal activities such as prostitution, money laundering, and corruption, violence is the most common act perpetrated by them.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>36","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS","question":"Use the dialogue below to answer the question.    Tim: Jim, let's go to the hospital and confirm our  HIV  status.  Jim: Really? Does my face resemble that of someone with  HIV ?  After all, I am too poor to engage in illicit sex, drug abuse nor keep numerous partners like you do.  Tim: It is more than what you think, Jim. You suffer other noticeable symptoms which makes me suspicious of your status.  Jim:  Okay, just to satisfy your curiosity, let's go.    From the above dialogue, noticeable symptoms Tim must have observed about Jim include the following except","images":[],"options":{"A":"profuse night sweats.","B":"persistent diarrhoea.","C":"increase in appetite","D":"usual fatigue"},"answer":"C","explanation":"The dialogue does not provide any specific symptoms that Tim observed in Jim. However, the options provided are common symptoms of HIV. Among these symptoms, an increase in appetite is not typically associated with HIV. HIV often causes loss of appetite. Therefore, the correct answer is 'increase in appetite'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>37","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"Use the dialogue below to answer the question.    Tim: Jim, let's go to the hospital and confirm our  HIV  status.  Jim: Really? Does my face resemble that of someone with  HIV ?  After all, I am too poor to engage in illicit sex, drug abuse nor keep numerous partners like you do.  Tim: It is more than what you think, Jim. You suffer other noticeable symptoms which makes me suspicious of your status.  Jim:  Okay, just to satisfy your curiosity, let's go.    Individual like Jim in the story above who believe HIV carriers are selective, can get enlightenment through","images":[],"options":{"A":"effective fasting and prayer.","B":"youth empowerment programme.","C":"sex and civic education.","D":"popular participation."},"answer":"C","explanation":"The dialogue suggests that Jim has misconceptions about how HIV is transmitted. He believes that only certain types of people (those who engage in illicit sex, drug abuse, or have numerous partners) can contract HIV. This is a misunderstanding. HIV can affect anyone, regardless of their lifestyle. Therefore, the best way for Jim to correct his misconceptions is through education, specifically sex and civic education, which would provide accurate information about HIV transmission and prevention.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>38","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"Which of the following is not a function of the judicial arm of government?","images":[],"options":{"A":"Interpretation of the law","B":"Judicial review","C":"Checking of arbitrariness","D":"Initiation of bills"},"answer":"D","explanation":"The judicial arm of government is responsible for interpreting the law, conducting judicial reviews, and checking arbitrariness. However, the initiation of bills is not a function of the judiciary but rather the legislature. The legislature is responsible for making laws, which includes the initiation of bills.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>39","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The officials of the administrative agency of the state that are most active in governance belongs to the","images":[],"options":{"A":"Legislative organ","B":"Judicial organ","C":"Executive organ","D":"Civil societies"},"answer":"C","explanation":"The officials of the administrative agency of the state that are most active in governance belong to the executive organ. The executive branch of government is responsible for implementing and enforcing laws, which includes the administration of public policy. This makes them the most active in governance.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>40","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM","question":"One major reason some Nigerian youths join cult groups is","images":[],"options":{"A":"inadequate religious and moral instruction","B":"poor welfare programme for students.","C":"inadequate support from guardians and parents.","D":"prevalence of corruption among political elites"},"answer":"A","explanation":"The major reason some Nigerian youths join cult groups is due to inadequate religious and moral instruction. This is because a strong moral and religious foundation can help guide a person's actions and decisions, and prevent them from engaging in harmful activities such as joining a cult. The other options, while they may contribute to the problem, are not the main reason.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>41","subject":"Civic Education","year":"2022","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS","question":"All the following are aims of youth empowerment scheme except","images":[],"options":{"A":"Reduction of youth delinquency","B":"Promotion of self-reliance","C":"Maximization of profit","D":"Building of self-esteem"},"answer":"C","explanation":"The aim of youth empowerment schemes is not to maximize profit. Youth empowerment schemes are designed to equip young people with the skills, knowledge, and opportunities they need to be productive members of society. This includes reducing youth delinquency, promoting self-reliance, and building self-esteem. Maximizing profit is typically a goal of businesses, not empowerment programs.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>42","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"A situation where only 35% of 80 million registered voters participated in a general election, is an indication of political","images":[],"options":{"A":"instability","B":"exclusiveness","C":"apathy","D":"socialization"},"answer":"C","explanation":"Political apathy refers to the indifference on the part of any citizen of any country with regard to their attitude towards political activities. A low voter turnout, such as 35% of 80 million registered voters participating in a general election, is a clear indication of political apathy. This is because a significant number of registered voters did not participate in the election, showing a lack of interest or concern in the political process.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>43","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"The organizations working against dictatorship and mounting of campaigns for effective civil rule are called","images":[],"options":{"A":"professional bodies.","B":"religious institutions.","C":"civil societies","D":"political parties"},"answer":"C","explanation":"Civil societies are organizations or groups that work in the interest of the citizens but operate outside of the government. They include non-governmental organizations (NGOs), community groups, women's organizations, faith-based organizations, professional associations, trade unions, self-help groups, social movements, business associations, coalitions and advocacy groups. They often work against dictatorship and mount campaigns for effective civil rule, advocating for human rights, social or political change.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>44","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY","question":"Use the diagram below to answer the question        In the democratic government structure, the portion marked x in the diagram is occupied by the","images":["data:image/png;base64,"],"options":{"A":"press","B":"judiciary","C":"civil societies","D":"political parties"},"answer":"B","explanation":"The judiciary is the third arm of government. The presidency represents the executive arm while the national assembly represents the legislative arm.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>45","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Use the diagram below to answer the question      The major function of the activity of the occupiers of the marked x in the diagram is to","images":["data:image/png;base64,"],"options":{"A":"interpret laws.","B":"execute policies.","C":"make bye laws","D":"formulate policies"},"answer":"A","explanation":"The major function of the judiciary is to interpret the law. The executive is charged with executing policies while the legislature formulates policies. Bye laws are made by local governments.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>46","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC","question":"Which of the following is not is not a problem of civil society?","images":[],"options":{"A":"Leadership struggle","B":"Poor funding","C":"Planning to capture political power","D":"Embezzlement of funds"},"answer":"C","explanation":"Civil societies are typically non-governmental organizations that are involved in the public sphere, expressing the interests and will of their members. They are not involved in capturing political power, which is the domain of political parties. Therefore, planning to capture political power is not a problem of civil society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>47","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"One of the major complaint against the public service is","images":[],"options":{"A":"Inefficiency","B":"Victimization","C":"Discrimination","D":"Election rigging"},"answer":"A","explanation":"Public service refers to services provided by government to its citizens, either directly or by financing provision of services. One of the major complaints against the public service is inefficiency. This could be due to bureaucracy, lack of resources, or poor management. Inefficiency in public service can lead to delays, poor quality of service, and dissatisfaction among the public.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>48","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"From which of the following sources are constitutional provisions not derived?","images":[],"options":{"A":"Statutory sources","B":"Customary sources","C":"Judicial Precedence","D":"Story book"},"answer":"D","explanation":"Constitutional provisions are derived from statutory sources, customary sources, and judicial precedence. These are all legal sources that contribute to the formation and interpretation of a constitution. Statutory sources refer to laws enacted by a legislative body. Customary sources refer to long-standing practices and traditions that have been recognized by the courts and have the force of law. Judicial precedence refers to the principle that the decision of a higher court should serve as a guide or precedent for the decision of a lower court in similar cases. However, a story book is not a source of constitutional provisions. It's a book containing a collection of stories, usually for children, and has no legal bearing or contribution to constitutional provisions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2022>49","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The head of the judicial arm of government in Nigeria is the","images":[],"options":{"A":"Chief justice","B":"Supreme leader","C":"Chief of staff","D":"Chief Magistrate"},"answer":"A","explanation":"The head of the judicial arm of government in Nigeria is the Chief Justice. The Chief Justice is the highest-ranking judge who presides over the Supreme Court in Nigeria. The Supreme Leader is a title more commonly used in countries with a theocratic government structure and is not applicable to Nigeria's democratic system. The Chief of Staff is an administrative position, often in the executive branch of government, and does not head the judiciary. The Chief Magistrate is a judicial officer but does not head the judiciary.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2022>50","subject":"Civic Education","year":"2022","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The composition of National Assembly of the Federal Republic of Nigeria could be termed","images":[],"options":{"A":"unicameral","B":"collegial","C":"bicameral","D":"hierarchical"},"answer":"C","explanation":"The composition of the National Assembly of the Federal Republic of Nigeria is bicameral because it consists of two houses: the Senate and the House of Representatives. The term 'bicameral' refers to a legislative body that has two branches or chambers.","marks":"1","difficulty":"1"}];